  query MetaobjectsReadSchema {
    queryRoot: __type(name: "QueryRoot") {
      fields {
        name
        args {
          name
          type {
            kind
            name
            ofType {
              kind
              name
              ofType {
                kind
                name
              }
            }
          }
        }
        type {
          kind
          name
          ofType {
            kind
            name
          }
        }
      }
    }
    metaobjectDefinition: __type(name: "MetaobjectDefinition") {
      fields {
        name
      }
    }
    metaobject: __type(name: "Metaobject") {
      fields {
        name
      }
    }
  }

#graphql
  #graphql
  #graphql
  fragment MetaobjectReadFields on Metaobject {
    id
    handle
    type
    displayName
    updatedAt
    capabilities {
      publishable {
        status
      }
      onlineStore {
        templateSuffix
      }
    }
    fields {
      key
      type
      value
      jsonValue
      definition {
        key
        name
        required
        type {
          name
          category
        }
      }
    }
    titleField: field(key: "title") {
      key
      type
      value
      jsonValue
      definition {
        key
        name
        required
        type {
          name
          category
        }
      }
    }
  }

  fragment MetaobjectDefinitionReadFields on MetaobjectDefinition {
    id
    type
    name
    description
    displayNameKey
    access {
      admin
      storefront
    }
    capabilities {
      publishable {
        enabled
      }
      translatable {
        enabled
      }
      renderable {
        enabled
      }
      onlineStore {
        enabled
      }
    }
    fieldDefinitions {
      key
      name
      description
      required
      type {
        name
        category
      }
      validations {
        name
        value
      }
    }
    hasThumbnailField
    metaobjectsCount
    standardTemplate {
      type
      name
    }
    metaobjects(first: 10) {
      edges {
        cursor
        node {
          ...MetaobjectReadFields
        }
      }
      nodes {
        ...MetaobjectReadFields
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }

  query MetaobjectDefinitionByMissingType($type: String!) {
